```js
let credKey;
try {
  credKey = crypto.createHash('sha256').update(fs.realpathSync(credPath)).digest('hex').slice(0, 12);
} catch (e) {
  console.error(`usage unavailable: ${e.message}`);
  process.exit(2);
}
```

